#!/usr/bin/env node
/*
 * Removes generated test workspace directories (those ending in -test or matching known test artifacts)
 * to keep the repo root clean. Safe to run repeatedly.
 */
const fs = require('fs-extra');
const path = require('path');

// Directories considered generated by tests / sample runs
const PATTERN_SUFFIX = /-test$/;
const EXTRA_NAMES = new Set([
  'existing-dir', // from duplicate directory test
  'my-workspace', // sample init run
]);

async function main() {
  const root = process.cwd();
  const entries = await fs.readdir(root);
  const targets = entries.filter((name) => {
    const full = path.join(root, name);
    return fs.statSync(full).isDirectory() && (
      PATTERN_SUFFIX.test(name) || EXTRA_NAMES.has(name)
    ) && !isSourceOrConfig(name);
  });

  if (!targets.length) {
    console.log('No generated test workspace directories found.');
    return;
  }

  for (const t of targets) {
    const full = path.join(root, t);
    try {
      await fs.remove(full);
      console.log(`Removed ${t}`);
    } catch (err) {
      console.error(`Failed to remove ${t}:`, err.message);
    }
  }
}

function isSourceOrConfig(name) {
  return [
    'src','docs','bin','coverage','node_modules','examples','scripts'
  ].includes(name);
}

main().catch(err => {
  console.error('Cleanup script error:', err);
  process.exit(1);
});
